# Worked focus: fp-referential-transparency — Test whether an expression can be replaced by its value without changing program behavior.
def discounted(order: dict, rate: float) -> dict:
    before = repr(order)
    result = {**order, "total": round(order["subtotal"] * (1 - rate), 2)}
    assert repr(order) == before
    return result

order = {"subtotal": 24, "tags": ("member",)}
assert discounted(order, 0.1) == discounted(order, 0.1)

